const d=document.getElementById("hamburger"),e=document.getElementById("mobile-menu"),s=document.getElementById("hamburger-icon"),n=document.getElementById("close-icon");d?.addEventListener("click",()=>{!e?.classList.contains("hidden")?(e?.classList.add("hidden"),s?.classList.remove("hidden"),n?.classList.add("hidden")):(e?.classList.remove("hidden"),s?.classList.add("hidden"),n?.classList.remove("hidden"))});
